# ============================================================
# LaTeX Tokenizer with full grammar-aware token vocabulary
# ============================================================

class LaTeXTokenizer:
    """Tokenizer that respects LaTeX commands as atomic units."""
    STRUCTURAL_TOKENS = {'\\frac', '\\sqrt', '\\sum', '\\int', '\\prod',
                         '\\lim', '\\log', '\\sin', '\\cos', '\\tan',
                         '\\left', '\\right', '\\overline', '\\underline',
                         '\\hat', '\\bar', '\\vec', '\\dot', '\\ddot',
                         '\\mathbb', '\\mathcal', '\\mathrm', '\\mathbf'}

    REQUIRES_BRACE = {'^', '_', '\\frac', '\\sqrt', '\\overline',
                      '\\underline', '\\hat', '\\bar', '\\vec',
                      '\\dot', '\\ddot', '\\mathbb', '\\mathcal',
                      '\\mathrm', '\\mathbf'}

    def __init__(self):
        self.special_tokens = ['<pad>', '<sos>', '<eos>', '<unk>']
        self.vocab: Dict[str, int] = {t: i for i, t in enumerate(self.special_tokens)}
        self.reverse_vocab: Dict[int, str] = {i: t for t, i in self.vocab.items()}

    def tokenize(self, latex: str) -> List[str]:
        """Convert a LaTeX string into a list of tokens."""
        tokens = []
        i = 0
        latex = latex.strip()
        while i < len(latex):
            if latex[i] == ' ':
                i += 1
                continue
            if latex[i] == '\\':
                j = i + 1
                if j < len(latex) and latex[j].isalpha():
                    while j < len(latex) and latex[j].isalpha():
                        j += 1
                elif j < len(latex):
                    j += 1
                tokens.append(latex[i:j])
                i = j
            elif latex[i].isdigit():
                j = i
                while j < len(latex) and (latex[j].isdigit() or latex[j] == '.'):
                    j += 1
                tokens.append(latex[i:j])
                i = j
            else:
                tokens.append(latex[i])
                i += 1
        return tokens

    def build_from_corpus(self, corpus: List[str]):
        """Build vocabulary from a list of LaTeX strings."""
        token_counts = Counter()
        for text in tqdm(corpus, desc="Building vocab", leave=False):
            token_counts.update(self.tokenize(text))
        for token, _ in token_counts.most_common():
            if token not in self.vocab:
                self.vocab[token] = len(self.vocab)
        self.reverse_vocab = {i: t for t, i in self.vocab.items()}
        print(f"Vocabulary built: {len(self.vocab)} tokens")

    def encode(self, tokens: List[str]) -> List[int]:
        return [self.vocab.get(t, self.vocab['<unk>']) for t in tokens]

    def decode(self, indices: List[int], skip_special: bool = True) -> str:
        result = []
        for idx in indices:
            t = self.reverse_vocab.get(idx, '<unk>')
            if skip_special and t in self.special_tokens:
                continue
            if t == '<eos>':
                break
            result.append(t)
        return ' '.join(result)

    @property
    def pad_id(self) -> int: return self.vocab['<pad>']
    @property
    def sos_id(self) -> int: return self.vocab['<sos>']
    @property
    def eos_id(self) -> int: return self.vocab['<eos>']
    @property
    def unk_id(self) -> int: return self.vocab['<unk>']
    def __len__(self) -> int: return len(self.vocab)

tokenizer = LaTeXTokenizer()
