# Unified Dataset - Supports ALL 4 dataset types
# ============================================================

class UnifiedDataset(Dataset):
    """
    Supports all 4 dataset types, auto-detecting HF vs file-based format.
    """
    def __init__(self, config: Config, tokenizer: LaTeXTokenizer,
                 dataset_type: str, augment: bool = True):
        self.config = config
        self.tokenizer = tokenizer
        self.samples = []
        self.dataset_type = dataset_type
        self.augment = augment
        self.aug_pipeline = get_train_augmentation(config.img_height, config.img_width) if augment else None
        self.hf_data = None
        self._latex_col = None
        self._img_col = None
        self._complexities = None

        path_map = {
            "im2latex": os.path.join(config.data_dir, "im2latex"),
            "mw": os.path.join(config.data_dir, "mathwriting"),
            "crohme": os.path.join(config.data_dir, "crohme"),
            "hme": os.path.join(config.data_dir, "hme100k"),
        }
        path = path_map.get(dataset_type, "")

        if not os.path.exists(path):
            print(f"WARNING: {dataset_type} path not found: {path}")
            return

        # Try loading as HuggingFace dataset first
        hf_info = os.path.join(path, "dataset_info.json")
        if os.path.exists(hf_info):
            try:
                self.hf_data = load_from_disk(path)
                cols = self.hf_data.column_names

                # Auto-detect latex column
                for c in ['latex', 'formula', 'label', 'text', 'annotation']:
                    if c in cols:
                        self._latex_col = c
                        break

                # Auto-detect image column
                for c in ['image', 'img', 'pixel_values']:
                    if c in cols:
                        self._img_col = c
                        break

                if self._latex_col:
                    for i in range(len(self.hf_data)):
                        self.samples.append(('hf', i))
                    print(f"{dataset_type}: {len(self.samples)} samples (HF, latex='{self._latex_col}', img='{self._img_col}')")
                else:
                    print(f"{dataset_type}: HF dataset but no latex column found in {cols}")
                    self.hf_data = None
            except Exception as e:
                print(f"{dataset_type}: HF load failed: {e}")
                self.hf_data = None

        # If not HF, try file-based loading
        if self.hf_data is None:
            self._load_file_based(path)
            if len(self.samples) > 0:
                print(f"{dataset_type}: {len(self.samples)} samples (file-based)")
            else:
                print(f"{dataset_type}: 0 samples found")

    def _load_file_based(self, base: str):
        """Search for label files + images in directory tree."""
        for root, dirs, files in os.walk(base):
            for f in files:
                if not f.endswith('.txt'):
                    continue
                fname_lower = f.lower()
                if not any(k in fname_lower for k in ['label', 'train', 'gt', 'annotation', 'caption']):
                    continue

                lbl_path = os.path.join(root, f)

                img_dir = root
                for d in list(dirs) + ['train_images', 'images', 'train', 'img', 'imgs']:
                    candidate = os.path.join(root, d)
                    if os.path.isdir(candidate):
                        img_dir = candidate
                        break

                self._parse_label_file(lbl_path, img_dir, root)

    def _parse_label_file(self, lbl_path: str, img_dir: str, lbl_dir: str):
        """Parse a label file and find corresponding images."""
        try:
            with open(lbl_path, 'r', encoding='utf-8') as f:
                for line in f:
                    line = line.strip()
                    if not line:
                        continue
                    if '\t' in line:
                        parts = line.split('\t', 1)
                    else:
                        parts = line.split(' ', 1)
                    if len(parts) < 2:
                        continue

                    fname, latex = parts[0].strip(), parts[1].strip()

                    found = False
                    search_dirs = [img_dir, lbl_dir]
                    for sd in search_dirs:
                        if found:
                            break
                        for ext in ['', '.jpg', '.png', '.bmp', '.jpeg', '.tif']:
                            ip = os.path.join(sd, fname + ext)
                            if os.path.exists(ip):
                                self.samples.append(('local', ip, latex))
                                found = True
                                break
        except Exception as e:
            pass

    def _get_latex(self, idx: int) -> str:
        entry = self.samples[idx]
        if entry[0] == 'hf':
            val = self.hf_data[entry[1]][self._latex_col]
            return str(val) if val is not None else ''
        return entry[2]

    def get_complexities(self) -> List[int]:
        if self._complexities is None:
            self._complexities = []
            for i in tqdm(range(len(self.samples)), desc=f"Complexity ({self.dataset_type})", leave=False):
                self._complexities.append(compute_structural_complexity(self._get_latex(i)))
        return self._complexities

    def __len__(self) -> int:
        return len(self.samples)

    def __getitem__(self, idx: int) -> Dict[str, Any]:
        entry = self.samples[idx]
        try:
            if entry[0] == 'hf':
                row = self.hf_data[entry[1]]
                latex = str(row[self._latex_col]) if row[self._latex_col] is not None else ''

                img = None
                if self._img_col and self._img_col in row:
                    img = row[self._img_col]

                if img is None:
                    img = Image.new('L', (self.config.img_width, self.config.img_height), 255)
                elif isinstance(img, str):
                    img = Image.open(img)
                elif not isinstance(img, Image.Image):
                    try:
                        img = Image.fromarray(np.array(img))
                    except:
                        img = Image.new('L', (self.config.img_width, self.config.img_height), 255)
            else:
                img = Image.open(entry[1])
                latex = entry[2]

            img_tensor = process_image(img, self.config.img_height, self.config.img_width,
                                       augment=self.augment, aug_pipeline=self.aug_pipeline)
            tokens = self.tokenizer.tokenize(latex)[:self.config.max_seq_len - 2]
            ids = [self.tokenizer.sos_id] + self.tokenizer.encode(tokens) + [self.tokenizer.eos_id]
            tree_pairs, _ = latex_to_tree(latex, self.tokenizer)
            complexity = compute_structural_complexity(latex)

            return {
                'image': img_tensor,
                'ids': torch.tensor(ids, dtype=torch.long),
                'tree': tree_pairs,
                'latex': latex,
                'length': len(ids),
                'complexity': complexity
            }
        except Exception:
            return {
                'image': torch.zeros(1, self.config.img_height, self.config.img_width),
                'ids': torch.tensor([self.tokenizer.sos_id, self.tokenizer.eos_id], dtype=torch.long),
                'tree': [], 'latex': '', 'length': 2, 'complexity': 0
            }

print("UnifiedDataset class defined.")

# ============================================================
# Curriculum Sampler and Collate
# ============================================================

class CurriculumSampler(Sampler):
    def __init__(self, dataset: Dataset, warmup_epochs: int = 10):
        self.dataset = dataset
        self.warmup_epochs = warmup_epochs
        self.epoch = 0
        self.n = len(dataset)
        if hasattr(dataset, 'get_complexities'):
            complexities = dataset.get_complexities()
        elif hasattr(dataset, 'datasets'):
            complexities = []
            for ds in dataset.datasets:
                if hasattr(ds, 'get_complexities'):
                    complexities.extend(ds.get_complexities())
                else:
                    complexities.extend([0] * len(ds))
        else:
            complexities = [0] * self.n
        self.sorted_indices = sorted(range(self.n), key=lambda i: complexities[i] if i < len(complexities) else 0)

    def set_epoch(self, epoch: int): self.epoch = epoch

    def __iter__(self):
        if self.epoch < self.warmup_epochs:
            fraction = min(1.0, 0.3 + 0.7 * (self.epoch / max(self.warmup_epochs, 1)))
            indices = list(self.sorted_indices[:max(1, int(self.n * fraction))])
            random.shuffle(indices)
            return iter(indices)
        indices = list(range(self.n))
        random.shuffle(indices)
        return iter(indices)

    def __len__(self):
        if self.epoch < self.warmup_epochs:
            return max(1, int(self.n * min(1.0, 0.3 + 0.7 * (self.epoch / max(self.warmup_epochs, 1)))))
        return self.n


def collate_fn(batch):
    batch = [x for x in batch if x is not None and x['length'] > 0]
    if not batch: return None
    return {
        'image': torch.stack([x['image'] for x in batch]),
        'ids': pad_sequence([x['ids'] for x in batch], batch_first=True, padding_value=tokenizer.pad_id),
        'length': torch.tensor([x['length'] for x in batch]),
        'tree': [x['tree'] for x in batch],
        'latex': [x['latex'] for x in batch],
        'complexity': torch.tensor([x['complexity'] for x in batch]),
    }

print("Sampler and collate defined.")

# --- LaTeX Grammar Constraints ---

class LaTeXGrammarConstraints:
    def __init__(self, tokenizer: LaTeXTokenizer):
        self.tokenizer = tokenizer
        self.vocab_size = len(tokenizer)

        self.lbrace_id = tokenizer.vocab.get('{', -1)
        self.rbrace_id = tokenizer.vocab.get('}', -1)
        self.eos_id = tokenizer.eos_id
        self.sos_id = tokenizer.sos_id
        self.pad_id = tokenizer.pad_id

        self.requires_brace_ids = set()
        for tok_str in tokenizer.REQUIRES_BRACE:
            if tok_str in tokenizer.vocab:
                self.requires_brace_ids.add(tokenizer.vocab[tok_str])

    def get_valid_mask(self, generated_ids: List[int]) -> torch.Tensor:
        mask = torch.ones(self.vocab_size, dtype=torch.bool)
        mask[self.pad_id] = False
        mask[self.sos_id] = False

        if not generated_ids:
            return mask

        last_id = generated_ids[-1]

        brace_depth = 0
        for tid in generated_ids:
            if tid == self.lbrace_id:
                brace_depth += 1
            elif tid == self.rbrace_id:
                brace_depth -= 1

        if last_id in self.requires_brace_ids and self.lbrace_id >= 0:
            mask[:] = False
            mask[self.lbrace_id] = True
            return mask

        if brace_depth <= 0 and self.rbrace_id >= 0:
            mask[self.rbrace_id] = False

        if brace_depth != 0:
            mask[self.eos_id] = False

        return mask

print("Grammar constraints defined.")

# --- Full TAMER Model ---

class TAMER(nn.Module):
    def __init__(self, vocab_size: int, config: Config):
        super().__init__()
        self.config = config
        self.vocab_size = vocab_size

        self.encoder = SwinEncoder(config.d_model, config)
        self.embedding = nn.Embedding(vocab_size, config.d_model, padding_idx=0)
        self.pos_encoding = PositionalEncoding1D(config.d_model, dropout=config.dropout)

        self.decoder_layers = nn.ModuleList([
            TAMERDecoderLayer(config.d_model, config.nhead, config.dim_feedforward, config.dropout)
            for _ in range(config.num_decoder_layers)
        ])
        self.decoder_norm = nn.LayerNorm(config.d_model)

        self.tree_module = TreeAwareModule(
            config.d_model,
            num_refine_layers=config.num_encoder_refine_layers,
            nhead=config.nhead
        )

        self.output_proj = nn.Linear(config.d_model, vocab_size)
        self._init_weights()

    def _init_weights(self):
        for p in self.output_proj.parameters():
            if p.dim() > 1:
                nn.init.xavier_uniform_(p)
        nn.init.normal_(self.embedding.weight, std=0.02)

    def _generate_causal_mask(self, sz: int, device: torch.device) -> torch.Tensor:
        return torch.triu(torch.full((sz, sz), float('-inf'), device=device), diagonal=1)

    def encode(self, images: torch.Tensor) -> torch.Tensor:
        return self.encoder(images)

    def decode(self, tgt_ids, memory, coverage=None):
        B, T = tgt_ids.shape
        S = memory.shape[1]

        tgt = self.pos_encoding(self.embedding(tgt_ids))
        causal_mask = self._generate_causal_mask(T, tgt.device)

        if coverage is None:
            coverage = torch.zeros(B, S, device=tgt.device)

        for layer in self.decoder_layers:
            tgt, attn_w, coverage = layer(tgt, memory, causal_mask, coverage)

        tgt = self.decoder_norm(tgt)
        logits = self.output_proj(tgt)
        tree_scores = self.tree_module(tgt)

        return logits, tree_scores, coverage, tgt

    def forward(self, images, tgt_ids):
        memory = self.encode(images)
        logits, tree_scores, coverage, _ = self.decode(tgt_ids, memory)
        return logits, tree_scores, coverage

print("TAMER model defined.")
